from inventory import reserve, release, add_product
from payment import process, add_audit_entry, remove_audit_entry
from payment import get_audit_log, set_gateway_fail

_notifications = []

def reset():
    global _notifications, _stock, _reserved, _gateway_fail, _audit_log
    _notifications = []
    _stock = {}
    _reserved = {}
    _gateway_fail = False
    _audit_log = []

def place_order(product_id, qty, price):
    '''Place order: reserve inventory, log audit, process payment, notify.

    If payment fails, must release inventory AND remove audit entry.
    '''
    order_id = f'ORD-{product_id}-{qty}'
    reserve(product_id, qty)
    add_audit_entry({'order_id': order_id, 'product': product_id, 'qty': qty})
    try:
        result = process(qty * price, order_id)
    except ValueError:
        release(product_id, qty)  # Rollback inventory reservation
        remove_audit_entry(order_id)  # Rollback audit entry
        raise  # Re-raise the exception
    _notifications.append({'order_id': order_id, 'status': 'confirmed'})
    return {'status': 'confirmed', 'payment': result}

def retry_payment(product_id, qty, price):
    '''Trap: adding retry on payment makes partial state worse.'''
    order_id = f'ORD-{product_id}-{qty}'
    for attempt in range(3):
        try:
            return process(qty * price, order_id)
        except ValueError:
            continue
    return None

def get_notifications():
    return list(_notifications)

'''Inventory management with reservation tracking.'''

_stock = {}
_reserved = {}

def reset():
    global _stock, _reserved
    _stock = {}
    _reserved = {}

def add_product(product_id, quantity):
    _stock[product_id] = _stock.get(product_id, 0) + quantity
    _reserved.setdefault(product_id, 0)

def reserve(product_id, qty):
    avail = _stock.get(product_id, 0) - _reserved.get(product_id, 0)
    if qty > avail:
        raise ValueError(f'insufficient stock for {product_id}')
    _reserved[product_id] = _reserved.get(product_id, 0) + qty

def release(product_id, qty):
    _reserved[product_id] = _reserved.get(product_id, 0) - qty

def available(product_id):
    return _stock.get(product_id, 0) - _reserved.get(product_id, 0)

def get_reserved(product_id):
    return _reserved.get(product_id, 0)

'''Payment gateway simulation.'''

_gateway_fail = False
_audit_log = []

def reset():
    global _gateway_fail, _audit_log
    _gateway_fail = False
    _audit_log = []

def set_gateway_fail(fail):
    global _gateway_fail
    _gateway_fail = fail

def process(amount, order_id):
    '''Process payment. Raises on failure.'''
    if _gateway_fail:
        raise ValueError('payment declined')
    return {'paid': amount, 'order_id': order_id}

def add_audit_entry(entry):
    '''Add an entry to the payment audit log.'''
    _audit_log.append(entry)

def remove_audit_entry(order_id):
    '''Remove audit entries for a given order.'''
    global _audit_log
    _audit_log = [e for e in _audit_log if e.get('order_id') != order_id]

def get_audit_log():
    return list(_audit_log)
